let select=e=>{const t=document.querySelector(`${e} > .select__header`),i=document.querySelectorAll(`${e} .select__option`);t.addEventListener("click",(function(){this.closest(e).classList.toggle("is-active")}));for(let r=0;r<i.length;r++)i[r].addEventListener("click",(function(){this.closest(e).classList.remove("is-active"),t.innerText=this.innerText}))};const photoSlider=new Swiper(".creo__slider-one",{loop:!0,navigation:{prevEl:".creo__btn-prev-one",nextEl:".creo__btn-next-one"},slidesPerView:5,spaceBetween:50,grabCursor:!0}),videoSlider=new Swiper(".creo__slider-two",{loop:!0,navigation:{prevEl:".creo__btn-prev-two",nextEl:".creo__btn-next-two"},slidesPerView:5,spaceBetween:50,grabCursor:!0}),blogSlider=new Swiper(".blog__slider",{navigation:{prevEl:".blog__btn-prev",nextEl:".blog__btn-next"},pagination:{el:".blog__pagination",clickable:!0},slidesPerView:4,spaceBetween:27,grabCursor:!0,slidesPerGroup:4}),reviewsSlider=new Swiper(".reviews__slider",{speed:500,effect:"fade",fadeEffect:{crossFade:!0},navigation:{prevEl:".reviews__slider-btn-prev",nextEl:".reviews__slider-btn-next"},pagination:{type:"fraction",el:".reviews__slider-pagination"}});select(".services__select");